import { NextRequest, NextResponse } from 'next/server';
import { decryptGHLSession, validateSessionData } from '@/lib/ghl/session-decrypt';
import { getEnvOrThrow } from '@/lib/env-validation';
import { createAdminClient } from '@/lib/supabase/admin';

/**
 * Decrypt GHL session key and create/update user session
 */
export async function POST(request: NextRequest) {
  try {
    const { sessionKey } = await request.json();

    if (!sessionKey) {
      return NextResponse.json(
        { error: 'Missing sessionKey parameter' },
        { status: 400 }
      );
    }

    // Get shared secret from environment
    const sharedSecret = getEnvOrThrow('GHL_SHARED_SECRET');

    // Decrypt session data
    let sessionData;
    try {
      sessionData = decryptGHLSession(sessionKey, sharedSecret);
    } catch (error) {
      console.error('Session decryption failed:', error);
      return NextResponse.json(
        { 
          error: 'Failed to decrypt session',
          details: error instanceof Error ? error.message : 'Unknown error',
          help: 'Verify GHL_SHARED_SECRET is configured correctly in Vercel'
        },
        { status: 401 }
      );
    }

    // Validate session data
    if (!validateSessionData(sessionData)) {
      return NextResponse.json(
        { error: 'Invalid session data - missing required fields' },
        { status: 400 }
      );
    }

    // Create Supabase admin client
    const supabase = createAdminClient();

    // Check if installation exists for this location
    const { data: installation } = await supabase
      .from('installations')
      .select('*')
      .eq('location_id', sessionData.locationId)
      .single();

    if (!installation) {
      return NextResponse.json(
        { 
          error: 'App not installed',
          locationId: sessionData.locationId,
          message: 'Please install the app first from the GHL marketplace'
        },
        { status: 403 }
      );
    }

    if (installation.status !== 'active') {
      return NextResponse.json(
        { 
          error: 'Installation inactive',
          status: installation.status,
          message: 'This app installation is not active'
        },
        { status: 403 }
      );
    }

    // Create or get user in Supabase Auth
    const userEmail = sessionData.email || `${sessionData.userId}@ghl.internal`;
    
    const { data: authData, error: authError } = await supabase.auth.admin.createUser({
      email: userEmail,
      email_confirm: true,
      user_metadata: {
        ghl_user_id: sessionData.userId,
        location_id: sessionData.locationId,
        company_id: sessionData.companyId,
        name: sessionData.name,
        role: sessionData.role,
      },
    });

    if (authError && !authError.message.includes('already registered')) {
      console.error('Supabase auth error:', authError);
      return NextResponse.json(
        { error: 'Failed to create user session' },
        { status: 500 }
      );
    }

    // Get or create user record
    const userId = authData?.user?.id;
    if (userId) {
      await supabase
        .from('users')
        .upsert({
          auth_id: userId,
          ghl_user_id: sessionData.userId,
          location_id: sessionData.locationId,
          company_id: sessionData.companyId,
          email: userEmail,
        }, {
          onConflict: 'ghl_user_id'
        });
    }

    // Generate session token
    const { data: sessionTokenData, error: sessionError } = await supabase.auth.admin.generateLink({
      type: 'magiclink',
      email: userEmail,
    });

    if (sessionError) {
      console.error('Session generation error:', sessionError);
      return NextResponse.json(
        { error: 'Failed to generate session' },
        { status: 500 }
      );
    }

    return NextResponse.json({
      success: true,
      locationId: sessionData.locationId,
      companyId: sessionData.companyId,
      userId: sessionData.userId,
      session: sessionTokenData,
    });

  } catch (error) {
    console.error('Session authentication error:', error);
    
    if (error instanceof Error && error.message.includes('Missing required environment variable')) {
      return NextResponse.json(
        { 
          error: 'Server configuration error',
          details: error.message,
          help: 'Please ensure GHL_SHARED_SECRET is configured in Vercel project settings.'
        },
        { status: 500 }
      );
    }
    
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}